import java.util.ArrayList;
import java.util.List;

import static org.junit.jupiter.api.Assertions.assertIterableEquals;

public class NodeTraversor_traverse_1_Test {

    @Test
    @DisplayName("Replaces a non-root child in head (parent != null && origSize == new size) and continues traversal on replacement")
    public void test_TC11() {
        // Setup a root with one child to trigger replacement in head
        Element root = new Element("div");
        Element child = new Element("p");
        root.appendChild(child);
        List<String> log = new ArrayList<>();
        NodeVisitor visitor = new NodeVisitor() {
            @Override
            public void head(Node node, int depth) {
                // record visit and replace the child to satisfy origSize == new size branch
                log.add(node.nodeName() + ":head:" + depth);
                if (node == child) {
                    node.replaceWith(new Element("q"));
                }
            }
            @Override
            public void tail(Node node, int depth) {
                log.add(node.nodeName() + ":tail:" + depth);
            }
        };
        // Execute traversal
        NodeTraversor.traverse(visitor, new Elements(root)); // Changed to use Elements
        // Expect head on root, head on original child p, head and tail on replacement q at depth 1, then tail on root
        List<String> expected = List.of(
            "div:head:0",
            "p:head:1",
            "q:head:1",
            "q:tail:1",
            "div:tail:0"
        );
        assertIterableEquals(expected, log);
    }

